import { useFadeIn } from "../../../../Downloads/Downloads/portfolio-react/portfolio-react/src/hooks";

/**
 * Wraps children in a div that fades in when scrolled into view.
 * Uses the global .fade / .fade.show CSS classes.
 *
 * @prop {number} delay  - transition-delay in seconds (default 0)
 * @prop {object} style  - extra inline styles
 * @prop {string} className - extra class names
 */
export default function FadeIn({ children, delay = 0, style = {}, className = "" }) {
  const ref = useFadeIn();

  return (
    <div
      ref={ref}
      className={`fade ${className}`.trim()}
      style={{ transitionDelay: `${delay}s`, ...style }}
    >
      {children}
    </div>
  );
}
